const b = $input.first().json.body || {};
const clean = s => String(s || '').replace(/[^a-zA-Z0-9 \-\.,'éàüöä]/g, '').slice(0, 80);
return [{ json: {
  country_code: clean(b.country_code).toUpperCase().slice(0,2) || 'XX',
  country_name: clean(b.country_name) || 'Unknown',
  session_id:   clean(b.session_id).slice(0,128) || 'unknown'
}}];
